  {(layer, graph) => (
    <div onClick={() => layer.hide()}>
      Blocks: {graph.api.getBlocks().length}
    </div>
  )}
</GraphPortal>

class MyLayer extends Layer {
  constructor(props) {
    super({ ...props, canvas: { zIndex: 10, respectPixelRatio: true } });
  }
  protected afterInit(): void {
    this.onGraphEvent('camera-change', this.handleCamera);
    super.afterInit();
  }
  public render(ctx: CanvasRenderingContext2D): void {
    this.resetTransform();
    ctx.fillStyle = 'red';
    ctx.fillRect(0, 0, 100, 100);
  }
}

// Add via graph
graph.addLayer(MyLayer, { myProp: 'value' });
